%keys;
%hits;
sub GetFunctionName
{
   my ($name) = @_;
   return (substr $name ,0, (index $name, " ")) ;
}
sub IsStringClass
{
   my ($name) = @_;
   $_ = $name;
   return 
(/^((nsString|nsStr|nsAutoString|nsCString|nsCAutoString):)|CopyChars[12]To[12]/
) ;
}
$key = "";
$count = 0;
#
# state 0 begin, get ENDSTACK
# state 1 get ERRORTEXT
# state 2 get BEGINDATA
# state 3 get ENDDATA
# state 4 get BEGINSTACK
#
open (INDEX, ">index.html") || die "cannot open index.html";
open (OUTPUT, ">output.html") || die "cannot open output.html";
printf OUTPUT "<PRE>";
$case = 0;
$data="";
while(<STDIN>)
{
  $data .= $_ ;
  if(0 == $state) {
    if(/ERRORTEXT/) {
       # do some thing
       $state = 1;
    }
  } elsif (1 == $state) {
    if(/BEGINDATA/) {
       $state = 2;
    }
  } elsif (2 == $state) {
    if(/ENDDATA/) {
       $state = 3;
    } else {
    }
  } elsif (3 == $state) {
    if(/BEGINSTACK/) {
       $state = 4;
    }
  } elsif (4 == $state) {
    if(/ENDSTACK/) {
       if(! exists($keys{$key})){
         $case = $case +1;
         printf OUTPUT "<A NAME=case" . $case . ">\n";
         printf OUTPUT "<H2>Case: $case <\/H2>\n";
         printf OUTPUT "<FONT COLOR=red>$key<\/FONT>\n";
         $keys{$key}  = $case;
         $hits{$key}  = 1;
         printf OUTPUT $data ;
         printf OUTPUT "\n<HR>\n";
       } else {
         $hits{$key}  = $hits{$key} + 1;
       }
       $data = "";
       $state = 0;
    } else {

      $func  = &GetFunctionName($_);
      if (&IsStringClass($func)){
        $key =  $func . "\n";
        $count = 0;
      } else {
        if($count < 3) {
           $key .= $func . "\n";
           $count =  $count + 1;
        }
      } # else of IsStringClass
    } # else of /ENDSTACK/
  } # elsif 4 == $state
} # while

printf OUTPUT "<\/PRE>";
